// Validate that all required fields are present
const body = $input.first().json.body || $input.first().json;

const required = [
  { key: 'referrer_name',  label: 'Your Name' },
  { key: 'referrer_email', label: 'Your Email' },
  { key: 'referred_name',  label: 'Lead Name' },
  { key: 'referred_email', label: 'Lead Email' }
];

const missing = required
  .filter(f => !body[f.key] && !body[f.key.replace('referred_', 'lead_')])
  .map(f => f.label);

if (missing.length > 0) {
  return [{ json: { valid: false, missing_fields: missing, body } }];
}

return [{ json: { valid: true, body } }];

// Extract and structure referral data
const body = $input.first().json.body;

const referral = {
  referrer_name:    body.referrer_name    || body.your_name    || 'Unknown Referrer',
  referrer_email:   body.referrer_email   || body.your_email   || '',
  referrer_company: body.referrer_company || body.your_company || '',

  lead_name:    body.referred_name    || body.lead_name    || 'Unknown Lead',
  lead_email:   body.referred_email   || body.lead_email   || '',
  lead_company: body.referred_company || body.lead_company || '',
  lead_phone:   body.referred_phone   || body.lead_phone   || '',

  referral_notes:  body.notes   || body.message || '',
  referral_source: 'B2B Referral Program',
  submission_date: new Date().toISOString(),
  referral_id:     'REF-' + Date.now()
};

return [{ json: referral }];
